if (! function_exists('data_moving_average')) {
    function data_moving_average($values, $window = null, $mode = null)
    {
        if (!is_array($values) || count($values) < 2) {
            return json_encode(['error' => 'At least 2 values required', 'result' => $values ?? []]);
        }
        $window = isset($window) && $window > 0 ? (int)$window : 3;
        $mode = isset($mode) ? $mode : 'simple';
        $n = count($values);
        $result = [];
        $original = $values;

        if ($mode === 'exponential') {
            $alpha = 2.0 / ($window + 1);
            $ema = array_sum(array_slice($values, 0, min($window, $n))) / min($window, $n);
            $result[] = round($ema, 6);
            for ($i = 1; $i < $n; $i++) {
                $ema = $alpha * $values[$i] + (1 - $alpha) * $ema;
                $result[] = round($ema, 6);
            }
        } elseif ($mode === 'centered') {
            if ($window % 2 === 0) $window++;
            $half = (int)(($window - 1) / 2);
            for ($i = 0; $i < $n; $i++) {
                $start = max(0, $i - $half);
                $end = min($n - 1, $i + $half);
                $slice = array_slice($values, $start, $end - $start + 1);
                $result[] = round(array_sum($slice) / count($slice), 6);
            }
        } elseif ($mode === 'median') {
            if ($window % 2 === 0) $window++;
            $half = (int)(($window - 1) / 2);
            for ($i = 0; $i < $n; $i++) {
                $start = max(0, $i - $half);
                $end = min($n - 1, $i + $half);
                $slice = array_slice($values, $start, $end - $start + 1);
                sort($slice);
                $mid = (int)(count($slice) / 2);
                $result[] = round($slice[$mid], 6);
            }
        } elseif ($mode === 'simple') {
            for ($i = 0; $i < $n; $i++) {
                $start = max(0, $i - $window + 1);
                $slice = array_slice($values, $start, $i - $start + 1);
                $result[] = round(array_sum($slice) / count($slice), 6);
            }
        } else {
            return json_encode(['error' => "Unknown mode: '$mode'. Valid modes: simple, centered, exponential, median"]);
        }

        return json_encode([
            'original' => array_map(function($v) { return round($v, 6); }, $original),
            'smoothed' => $result,
            'window' => $window,
            'mode' => $mode,
            'n' => $n,
        ]);
